module ring_counter_5(
   input                clk,
   input                rst,

   output reg [4:0]     Q
);
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always@(posedge clk or posedge dbg_halt) begin
        if(rst) Q <= 5'b00001;
        else Q <= {Q[3:0], Q[4]};
    end
endmodule
